impl<R: PasswordRequirementsProjectionRepository> PasswordRequirementsEventHandler for PasswordRequirementsProjector<R> {

    async fn on_created(&self, event: PasswordRequirementsCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = PasswordRequirementsProjection::new(
            event.id,
            event.min_length,
            event.max_length,
            event.require_uppercase,
            event.require_lowercase,
            event.require_digits,
            event.require_special_characters,
            event.require_no_common_passwords,
            event.require_no_user_info,
            event.min_entropy_bits,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: PasswordRequirementsUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.min_length = event.min_length;
            projection.max_length = event.max_length;
            projection.require_uppercase = event.require_uppercase;
            projection.require_lowercase = event.require_lowercase;
            projection.require_digits = event.require_digits;
            projection.require_special_characters = event.require_special_characters;
            projection.require_no_common_passwords = event.require_no_common_passwords;
            projection.require_no_user_info = event.require_no_user_info;
            projection.min_entropy_bits = event.min_entropy_bits;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: PasswordRequirementsDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

